INSERT INTO t_online_voting_acknowledgement (
    package_id, electorate_item_id, tenant_id, account_id, uid, opid,
    package_hash, acknowledgement_hash, unified_delivery_id, acknowledged_at
) VALUES (
    #{packageId}, #{electorateItemId}, #{tenantId}, #{accountId}, #{uid}, #{opid},
    #{packageHash}, #{acknowledgementHash}, #{unifiedDeliveryId}, #{acknowledgedAt}
)

mapper.select:
SELECT acknowledgement_id, package_id, electorate_item_id, tenant_id, account_id, uid, opid,
       package_hash, acknowledgement_hash, unified_delivery_id, acknowledged_at
FROM t_online_voting_acknowledgement
WHERE package_id = #{packageId}
  AND electorate_item_id = #{electorateItemId}
  AND tenant_id = #{tenantId}

